import{_ as a,c as t,o as i,ak as s,aq as r}from"./chunks/framework.DHLlVITf.js";const p=JSON.parse('{"title":"AireFrame Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireframe-v3-0-0.md","filePath":"aireblock-releases/aireframe-v3-0-0.md","lastUpdated":1781704033000}'),n={name:"aireblock-releases/aireframe-v3-0-0.md"};function o(l,e,c,u,h,d){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="aireframe-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+r+'"> AireFrame Release Notes</span> <a class="header-anchor" href="#aireframe-release-notes" aria-label="Permalink to “AireFrame Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 3.0.0<br><strong>Release Date:</strong> 17th June 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Linked Data Set Indicator — FRAME-2480</li><li>Bulk Structural Entity API — FRAME-2541</li><li>Bulk Subject API — FRAME-2543</li><li>Optimised Subject Access Filtering — FRAME-2562</li></ul><h4 id="⚡-improvements" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements" aria-label="Permalink to “⚡ Improvements”">​</a></h4><ul><li>Bulk Replace Subject Locations — FRAME-2539</li><li>Flexible Subject Launcher via Custom Field — FRAME-2565</li><li>Manual Structure Cache Clear Removed — FRAME-2551</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>False Stale Data Warning on Tab Revisit — FRAME-2483</li><li>Inconsistent User Name Theming — FRAME-2582</li></ul><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="linked-data-set-indicator-frame-2480" tabindex="-1">Linked Data Set Indicator (FRAME-2480) <a class="header-anchor" href="#linked-data-set-indicator-frame-2480" aria-label="Permalink to “Linked Data Set Indicator (FRAME-2480)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Single source data sets that are used within a Linked or Stacked Data Set now display their relationship clearly, rather than showing as &quot;Not Used&quot;. This prevents confusion when reviewing data set usage and avoids errors that could occur when attempting to delete a data set that is still in use indirectly.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now see at a glance whether a data set is part of a Linked or Stacked Data Set, making it much easier to understand how your data is connected and avoid accidentally removing something that is still in use.</p></div><h4 id="bulk-structural-entity-api-frame-2541" tabindex="-1">Bulk Structural Entity API (FRAME-2541) <a class="header-anchor" href="#bulk-structural-entity-api-frame-2541" aria-label="Permalink to “Bulk Structural Entity API (FRAME-2541)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new bulk upsert API endpoint has been introduced for structural entities, allowing multiple entities to be created or updated in a single request. All operations are wrapped in a transaction so that either everything succeeds or everything is rolled back. Child entities may be included in the same request as their parent, provided they appear after the parent in the array.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Large structural changes, such as setting up a new structural entity tree, can now be applied in one go rather than one record at a time, saving time and ensuring your data stays consistent throughout the process.</p></div><h4 id="bulk-subject-api-frame-2543" tabindex="-1">Bulk Subject API (FRAME-2543) <a class="header-anchor" href="#bulk-subject-api-frame-2543" aria-label="Permalink to “Bulk Subject API (FRAME-2543)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new bulk upsert API endpoint has been added for subjects, enabling multiple subjects to be created or updated in a single transactional request.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Importing or updating large numbers of subjects is now far quicker and more reliable.</p></div><h4 id="optimised-subject-access-filtering-frame-2562" tabindex="-1">Optimised Subject Access Filtering (FRAME-2562) <a class="header-anchor" href="#optimised-subject-access-filtering-frame-2562" aria-label="Permalink to “Optimised Subject Access Filtering (FRAME-2562)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The subject access architecture has been updated to integrate subjects, groups, and structural entities more closely with the AireFrame data model. This enables filtering to be performed directly within database queries rather than through additional application-layer processing.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>This change is primarily an internal architectural improvement and does not introduce any immediate functional changes. It provides the foundation for future performance and scalability enhancements in subject access filtering.</p></div><h3 id="⚡-improvements-1" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements-1" aria-label="Permalink to “⚡ Improvements”">​</a></h3><hr><h4 id="bulk-replace-subject-locations-frame-2539" tabindex="-1">Bulk Replace Subject Locations (FRAME-2539) <a class="header-anchor" href="#bulk-replace-subject-locations-frame-2539" aria-label="Permalink to “Bulk Replace Subject Locations (FRAME-2539)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>It is now possible to replace all subject locations under a particular structural entity in one operation. Both the source and destination location parameters are optional, so you can use this to either add all subjects to a new location, remove them from an existing one, or move them from one to another in a single step.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Moving all students from one year group to another — for example at the start of a new academic year — can now be done in a single bulk action rather than updating each subject individually.</p></div><h4 id="flexible-subject-launcher-via-custom-field-frame-2565" tabindex="-1">Flexible Subject Launcher via Custom Field (FRAME-2565) <a class="header-anchor" href="#flexible-subject-launcher-via-custom-field-frame-2565" aria-label="Permalink to “Flexible Subject Launcher via Custom Field (FRAME-2565)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The subject launcher has been updated to support launching a subject using any unique custom field value, via the URL pattern <code>/subject-launcher/[custom_field_key]/[custom_field_value]</code>. This replaces the previous external ID launcher with a more flexible, configuration-free approach.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now link directly to a subject&#39;s record using any unique identifier you already store, without needing to set up additional configuration.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="false-stale-data-warning-on-tab-revisit-frame-2483" tabindex="-1">False Stale Data Warning on Tab Revisit (FRAME-2483) <a class="header-anchor" href="#false-stale-data-warning-on-tab-revisit-frame-2483" aria-label="Permalink to “False Stale Data Warning on Tab Revisit (FRAME-2483)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A stale data warning icon was incorrectly appearing when navigating back to a tab that had been open for a period of time, even though no data had actually changed. The component was using the time of the most recent re-render rather than the time data was first fetched, causing the staleness check to give a false positive. This has been corrected so that the warning only appears when data genuinely requires refreshing.</p></div><h4 id="inconsistent-user-name-theming-frame-2582" tabindex="-1">Inconsistent User Name Theming (FRAME-2582) <a class="header-anchor" href="#inconsistent-user-name-theming-frame-2582" aria-label="Permalink to “Inconsistent User Name Theming (FRAME-2582)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The user name display in AireFrame was using a secondary text colour whilst the Portal was using the primary text colour, resulting in a visual inconsistency between the two interfaces. Both now use the correct primary text colour, bringing them in line with each other.</p></div>',38)])])}const b=a(n,[["render",o]]);export{p as __pageData,b as default};
